update esg.tb_user_info
   set email = #{email}
     , phone = #{phone}
     , signature = #{signature}

     , user_ps = #{userPs}
     , last_ps_date = now()
     , login_fail_cnt = 0

     , updated_at = now()
     , updated_by = #{userId}
 where user_id = #{userId};

update esg.tb_hr_info
   set sex_div = #{sexDiv}
     , birth_dt = #{birthDt}
     , zip_cd = #{zipCd}
     , addrs1 = #{addrs1}
     , addrs2 = #{addrs2}
     , updated_at = now()
     , updated_by = #{userId}
 where user_id = #{userId};

	update esg.tb_user_info
    set login_fail_cnt = coalesce(login_fail_cnt, 0) + 1
    where user_id = #{userId}

	update esg.tb_user_info
    set login_fail_cnt = 0
    where user_id = #{userId}

update esg.tb_user_info
set fcm_token = #{fcmToken}
where user_id = #{userId};
